/* thumbnail-loader.compat.fixed.js (standard, MARU engine aligned)
   - Primary: fetch Netlify Function feed: /.netlify/functions/feed?page=PAGEKEY
   - Secondary: fallback to assets/hero/psom.json (array) filtered by page
   - Renders into first element that has [data-psom-key]
*/
(function () {
  "use strict";

  var PAGEKEY_ATTR = "data-psom-key";
  var FEED_ENDPOINT = "/.netlify/functions/feed"; // standard for Netlify functions

  function getHost() {
    // Prefer a host inside the desktop right rail if present (prevents main layout from being overwritten)
    var railHost = document.querySelector(".right-rail [" + PAGEKEY_ATTR + "]");
    if (railHost) return railHost;
    return document.querySelector("[" + PAGEKEY_ATTR + "]");
  }
  function getPageKey() {
    var host = getHost();
    return host ? (host.getAttribute(PAGEKEY_ATTR) || "").trim() : "";
  }

  function guessLang() {
    try {
      if (window.IGDC_CORE && typeof window.IGDC_CORE.lang === "function") return window.IGDC_CORE.lang();
    } catch (e) {}
    var d = document.documentElement;
    return (d && (d.getAttribute("lang") || d.lang) || navigator.language || "en").toLowerCase().slice(0, 2);
  }

  function safeText(x) { return (x == null ? "" : String(x)); }
  function mapItem(x) {
    if (!x || typeof x !== "object") return null;
    return {
      title: safeText(x.title || x.name || x.label),
      href: safeText(x.href || x.url || "#"),
      img:  safeText(x.img || x.image || x.thumbnail || x.thumb || ""),
      desc: safeText(x.desc || x.description || x.category || "")
    };
  }

  function render(items) {
    var host = getHost();
    if (!host) return;

    var arr = Array.isArray(items) ? items : [];
    if (!arr.length) {
      host.innerHTML = '<div class="thumb-empty">No items</div>';
      return;
    }

    var html = arr.map(function (it) {
      var s = mapItem(it) || { title: "", href: "#", img: "", desc: "" };
      var img = s.img ? ('<img loading="lazy" src="' + s.img + '" alt=""/>') : "";
      var dsc = s.desc ? ('<div class="d">' + s.desc + "</div>") : "";
      return (
        '<a class="thumb-card" href="' + (s.href || "#") + '" target="_blank" rel="noopener noreferrer">' +
          img +
          '<div class="t">' + (s.title || "") + "</div>" +
          dsc +
        "</a>"
      );
    }).join("");

    host.innerHTML = html;
  }

  function parseFeedResponse(json) {
    // Expected from our feed.js: { ok:true, type:"feed", page, sections:[{items:[]}, ...] }
    if (!json || typeof json !== "object") return [];
    if (json.type === "feed" && Array.isArray(json.sections)) {
      var out = [];
      json.sections.forEach(function (sec) {
        if (sec && Array.isArray(sec.items)) out = out.concat(sec.items);
      });
      return out;
    }
    // Accept older shapes defensively
    if (Array.isArray(json.items)) return json.items;
    if (json.data && Array.isArray(json.data)) return json.data;
    if (json.data && Array.isArray(json.data.items)) return json.data.items;
    return [];
  }

  function fetchFeed(pageKey) {
    var url = FEED_ENDPOINT + "?page=" + encodeURIComponent(pageKey) + "&lang=" + encodeURIComponent(guessLang());
    try {
      if (window.IGDC_CORE && typeof window.IGDC_CORE.country === "function") {
        url += "&country=" + encodeURIComponent(window.IGDC_CORE.country());
      }
    } catch (e) {}
    return fetch(url, { credentials: "omit" })
      .then(function (r) { if (!r.ok) throw new Error("HTTP_" + r.status); return r.json(); })
      .then(function (json) {
        var items = parseFeedResponse(json);
        if (!items.length) throw new Error("EMPTY_FEED");
        return items;
      });
  }

  function fetchPsomFallback(pageKey) {
    // repo location: /assets/hero/psom.json
    var url = "/assets/hero/psom.json?v=" + Date.now();
    return fetch(url, { credentials: "omit" })
      .then(function (r) { if (!r.ok) throw new Error("HTTP_" + r.status); return r.json(); })
      .then(function (list) {
        if (!Array.isArray(list)) throw new Error("BAD_PSOM");
        var items = list
          .filter(function (x) { return x && String(x.page || "").trim() === pageKey; })
          .sort(function (a, b) { return (Number(b.weight || 0) - Number(a.weight || 0)); })
          .map(function (x) {
            return { title: x.title, url: x.url, category: x.category, image: x.image };
          });
        if (!items.length) throw new Error("EMPTY_PSOM");
        return items;
      });
  }

  function boot() {
    var pageKey = getPageKey();
    if (!pageKey) return;

    fetchFeed(pageKey)
      .then(render)
      .catch(function () { return fetchPsomFallback(pageKey).then(render); })
      .catch(function () { render([]); });
  }

  if (document.readyState === "loading") document.addEventListener("DOMContentLoaded", boot);
  else boot();

  window.__THUMB_VERSION__ = "maru-standard-20251222";
})();
